package com.samudhra.certificates.config;
import com.samudhra.certificates.entity.*; import com.samudhra.certificates.repository.*; import org.springframework.boot.CommandLineRunner; import org.springframework.context.annotation.*; import org.springframework.security.crypto.password.PasswordEncoder;
@Configuration public class DataInitializer { @Bean CommandLineRunner seed(OrganizationRepository organizations,UserRepository users,AdminRepository admins,PasswordEncoder passwords){return args->{if(admins.findByEmail("admin@samudhratechsolutions.com").isEmpty()){Admin admin=new Admin();admin.setName("Admin");admin.setEmail("admin@samudhratechsolutions.com");admin.setPassword(passwords.encode("admin123"));admins.save(admin);}if(users.findByEmail("admin@samudhratechsolutions.com").isEmpty()){Organization org=organizations.findAll().stream().findFirst().orElseGet(()->{Organization newOrg=new Organization();newOrg.setName("Samudhra Tech Solutions");return organizations.save(newOrg);});User user=new User();user.setName("Admin");user.setEmail("admin@samudhratechsolutions.com");user.setRole("ADMIN");user.setPasswordHash(passwords.encode("admin123"));user.setOrganization(org);users.save(user);}};}}
